export const MODEL_VERSION='CMO-Migraña v1.0 — julio de 2026';export const DIMENSIONS={demograficas:{label:'Variables demográficas',max:3},clinicas:{label:'Variables clínicas',max:10},farmacoterapeuticas:{label:'Variables farmacoterapéuticas',max:20},sociosanitarias:{label:'Variables sociosanitarias',max:6}};
const src='PDF no disponible en repositorio; pendiente de verificación literal';const opt=(id,label,score,definition,extra={})=>({id,label,score,definition,...extra});
export const VARIABLES=[['situacion_reproductiva','demograficas','Situación reproductiva','Embarazo, lactancia o deseo gestacional inminente clasifican automáticamente como Prioridad 1.',[opt('no_aplica','No',0,'No consta embarazo, lactancia ni deseo gestacional inminente.',{displayText:'No — 0 puntos'}),opt('si','Sí',0,'Embarazo, lactancia o deseo gestacional inminente.',{automaticPriorityReason:'situación reproductiva (embarazo, lactancia o deseo gestacional)',displayText:'Sí — Prioridad 1',detailScoreText:'Prioridad 1'})]],['edad','demograficas','Edad','Edad igual o inferior a 60 años: 0 puntos. Edad superior a 60 años: 1 punto (edad > 60). Los menores de 18 años deben valorarse mediante modelo CMO pediátrico.',[opt('menor_18','Menor de 18 años',0,'Requiere valoración mediante modelo pediátrico.',{pediatricReferral:true}),opt('hasta_60','Edad igual o inferior a 60 años',0,'Edad ≤60 años.'),opt('mayor_60','Edad superior a 60 años',1,'Edad >60 años.')]],['sexo','demograficas','Sexo','Sexo femenino: 1 punto. Cualquier otra opción: 0 puntos.',[opt('otro','Cualquier otra opción',0,'Sexo distinto de femenino, no informado como femenino o no consta.'),opt('femenino','Sexo femenino',1,'Sexo femenino.')]],['peso_estado_nutricional','demograficas','Índice de masa corporal','IMC igual o inferior a 30: 0 puntos. IMC superior a 30: 1 punto (IMC > 30).',[opt('imc_hasta_30','IMC igual o inferior a 30',0,'IMC ≤30.'),opt('imc_mayor_30','IMC superior a 30',1,'IMC >30.')]],['tipo_frecuencia_migrana','clinicas','Frecuencia y tipo de migraña','Categorías mutuamente excluyentes. Migraña crónica: Dolor de cabeza durante 15 o más días al mes, durante más de tres meses, de los cuales al menos 8 días presentan características de migraña.',[opt('episodica_baja','Migraña episódica de baja frecuencia, menos de 8 días al mes',0,'<8 días/mes.'),opt('episodica_alta','Migraña episódica de alta frecuencia, entre 8 y 14 días al mes',1,'8–14 días/mes.'),opt('cronica','Migraña crónica',2,'Dolor de cabeza durante 15 o más días al mes, durante más de tres meses, de los cuales al menos 8 días presentan características de migraña.')]],['impacto_discapacidad','clinicas','Impacto y discapacidad: HIT-6 y MIDAS','Impacto graduado en cuatro categorías; se conservan los criterios HIT-6/MIDAS ya definidos como apoyo orientativo.',[opt('poco_ninguno','Poco o ningún impacto',0,'Poco o ningún impacto funcional.'),opt('moderado','Impacto moderado',1,'Impacto funcional moderado.'),opt('sustancial','Impacto sustancial',2,'Impacto funcional sustancial.'),opt('severo','Impacto severo',3,'Impacto severo en HIT-6 (HIT-6 ≥60) y/o discapacidad severa en MIDAS (MIDAS ≥21); no acumula doble puntuación.')]],['comorbilidades_psiquiatricas','clinicas','Comorbilidades psiquiátricas','Comorbilidades psiquiátricas recogidas en el documento.',[opt('no','No',0,'No constan.'),opt('si','Sí',1,'Presencia de comorbilidad psiquiátrica.')]],['comorbilidades_no_psiquiatricas','clinicas','Comorbilidades no psiquiátricas','Categorías mutuamente excluyentes. Si concurren dolor crónico y comorbilidad cardiovascular, se aplica la categoría de mayor puntuación. Las comorbilidades cardiovasculares incluyen hipertensión arterial, infarto de miocardio o accidente cerebrovascular.',[opt('no','No',0,'No constan.'),opt('dolor_cronico','Paciente con dolor crónico',1,'Paciente con dolor crónico.'),opt('cardiovascular','Paciente con comorbilidades cardiovasculares',2,'Presencia de hipertensión arterial, infarto de miocardio o accidente cerebrovascular; no acumula con dolor crónico.')]],['pluripatologia','clinicas','Paciente pluripatológico','Paciente pluripatológico.',[opt('no','No',0,'No cumple definición.'),opt('si','Sí',1,'Paciente pluripatológico.')]],['paciente_naive','farmacoterapeuticas','Primera visita en Farmacia Hospitalaria','Paciente que acude a su primera visita con Farmacia Hospitalaria para establecer una pauta de tratamiento. Variable informativa: NA, no suma puntos.',[opt('no','No',null,'NA: variable informativa no puntuable.'),opt('si','Sí',null,'NA: variable informativa no puntuable.')]],['via_administracion','farmacoterapeuticas','Tipo de tratamiento preventivo','Categorías mutuamente excluyentes; la puntuación depende exclusivamente de la categoría indicada, no del número de medicamentos preventivos.',[opt('sin_preventivo','Paciente sin tratamiento preventivo',0,'Sin tratamiento preventivo.'),opt('oral','Paciente con tratamiento preventivo oral convencional',0,'Tratamiento preventivo oral convencional.'),opt('intravenosa','Paciente con tratamiento preventivo de administración intravenosa',1,'Tratamiento preventivo intravenoso.'),opt('subcutanea','Paciente con tratamiento preventivo de administración subcutánea',2,'Tratamiento preventivo subcutáneo.')]],['riesgo_interacciones','farmacoterapeuticas','Riesgo de interacciones','Riesgo de interacciones farmacológicas.',[opt('no','No',0,'Sin riesgo relevante.'),opt('si','Sí',2,'Riesgo relevante.')]],['fracasos_anti_cgrp','farmacoterapeuticas','Fracasos terapéuticos','Número de fracasos terapéuticos previos; 3 o más incluye cualquier entero ≥3.',[opt('ninguno','Ningún fracaso',0,'0 fracasos.'),opt('uno','1 fracaso',1,'1 fracaso.'),opt('dos','2 fracasos',2,'2 fracasos.'),opt('tres_o_mas','3 o más fracasos',3,'Cualquier valor entero ≥3.')]],['uso_excesivo_sintomatica','farmacoterapeuticas','Uso excesivo de medicación sintomática','Uso excesivo de medicación sintomática.',[opt('no','No',0,'No cumple criterios.'),opt('si','Sí',2,'Cumple criterios.')]],['cambios_tratamiento','farmacoterapeuticas','Cambios en el tratamiento','Cambios en el tratamiento.',[opt('no','No',0,'Sin cambios.'),opt('si','Sí',2,'Cambio relevante.')]],['efectos_adversos','farmacoterapeuticas','Efectos adversos','Opciones mutuamente excluyentes: sin efectos relevantes, efectos leves o efectos graves.',[opt('sin_relevantes','Sin efectos adversos relevantes',0,'No constan efectos adversos relevantes.'),opt('leves','Efectos adversos leves',1,'Efectos adversos leves.'),opt('graves','Efectos adversos graves',2,'Efectos adversos graves.')]],['falta_adherencia','farmacoterapeuticas','Falta de adherencia','Paciente con falta de adherencia: 3 puntos. Paciente adherente o sin evidencia de falta de adherencia: 0 puntos.',[opt('no','Paciente adherente o sin evidencia de falta de adherencia',0,'Paciente adherente o sin evidencia de falta de adherencia.'),opt('si','Paciente con falta de adherencia',3,'Paciente con falta de adherencia.')]],['medicamentos_alto_riesgo','farmacoterapeuticas','Medicamentos de alto riesgo','Referencia al listado de medicamentos de alto riesgo de ISMP-España.',[opt('no','No',0,'No constan.'),opt('si','Sí',4,'Según listado de medicamentos de alto riesgo de ISMP-España.')]],['consumo_cafeina','sociosanitarias','Consumo de cafeína','Consumo de cafeína.',[opt('adecuado','Sin consumo problemático',0,'Según documento.'),opt('alto','Consumo elevado/problemático',1,'Según documento.')]],['habitos_sueno','sociosanitarias','Hábitos del sueño','Paciente con hábitos del sueño alterados.',[opt('adecuados','No: paciente sin hábitos del sueño alterados',0,'Paciente sin hábitos del sueño alterados.'),opt('alterados','Sí: paciente con hábitos del sueño alterados',1,'Paciente con hábitos del sueño alterados.')]],['nivel_socioeconomico','sociosanitarias','Nivel socioeconómico','Condiciones socioeconómicas desfavorables según documento.',[opt('favorable','Sin condiciones desfavorables',0,'No constan.'),opt('desfavorable','Condiciones desfavorables',2,'Según definición del documento.')]],['formacion_paciente','sociosanitarias','Formación del paciente','Paciente con dificultades en la asimilación de pautas farmacológicas.',[opt('sin_dificultad','No: sin dificultades en la asimilación de pautas farmacológicas',0,'Sin dificultades en la asimilación de pautas farmacológicas.'),opt('dificultad','Sí: paciente con dificultades en la asimilación de pautas farmacológicas',2,'Paciente con dificultades en la asimilación de pautas farmacológicas.')]]].map(([id,dimension,label,definition,options])=>({id,dimension,label,required:true,sourcePage:src,definition,options}));
export const THRESHOLDS={p1Min:19,p2Min:15,p2Max:18,p3Max:14,totalMax:39};
export function normalizeAnswers(answers={}){const normalized={...answers};if(['embarazo','lactancia','deseo_gestacional'].includes(normalized.situacion_reproductiva))normalized.situacion_reproductiva='si';if(normalized.comorbilidades_no_psiquiatricas==='si')normalized.comorbilidades_no_psiquiatricas='dolor_cronico';if(normalized.comorbilidades_cardiovasculares==='si')normalized.comorbilidades_no_psiquiatricas='cardiovascular';delete normalized.comorbilidades_cardiovasculares;return normalized}export function calculatedPriority(score){return score>=THRESHOLDS.p1Min?1:score>=THRESHOLDS.p2Min?2:3}export const PERIODICITY={model:{always:['Al inicio del tratamiento.','Cuando exista un cambio en el tratamiento.'],byPriority:{1:'Cada 6 meses.',2:'Cada 12 meses.',3:'Cada 12 meses.'}},followUp:{always:['Visitas de seguimiento adecuadas para potenciar el acto unico asistencial y el seguimiento adecuado según complejidad asistencial del paciente y recursos del servicio de farmacia del centro.'],byPriority:{}}};
export const INTERVENTIONS={3:{'Seguimiento farmacoterapéutico':['Revisar el tratamiento preventivo y sintomático registrado y comprobar adecuación, efectividad, seguridad, interacciones, adherencia y persistencia.'],'Educación, formación y seguimiento del paciente':['Educar al paciente en objetivos del tratamiento, uso correcto de la medicación y registro de crisis, síntomas y consumo de medicación sintomática.'],'Coordinación con el equipo asistencial':['Documentar las intervenciones farmacéuticas en el registro local del caso y comunicar incidencias clínicas relevantes al equipo asistencial.']},2:{'Seguimiento farmacoterapéutico':['Revisar cambios de pauta, combinaciones terapéuticas, vías de administración de mayor complejidad y aparición de incidencias.'],'Educación, formación y seguimiento del paciente':['Reforzar educación individualizada y seguimiento de adherencia, tolerabilidad y expectativas terapéuticas.'],'Coordinación con el equipo asistencial':['Coordinar con Neurología y otros profesionales las necesidades de seguimiento derivadas de cambios terapéuticos o situación clínica.']},1:{'Seguimiento farmacoterapéutico':['Realizar seguimiento farmacoterapéutico intensivo en pacientes de mayor complejidad, con especial atención a seguridad, efectividad e interacciones.'],'Educación, formación y seguimiento del paciente':['Establecer educación y seguimiento estrecho del paciente y/o persona cuidadora ante alta complejidad o prioridad automática.'],'Coordinación con el equipo asistencial':['Consensuar con Neurología un plan de seguimiento farmacoterapéutico para los pacientes de mayor complejidad.']}};
function scoreValue(score){return typeof score==='number'&&Number.isFinite(score)?score:0}export function scoreCase(answers={},override){answers=normalizeAnswers(answers);const contributions=VARIABLES.map(v=>{const o=v.options.find(x=>x.id===answers[v.id]);return{dimension:v.dimension,variableId:v.id,variable:v.label,option:o?.label,score:o?.score,displayScore:o?o.score==null?'NA':o.score:undefined,missing:v.required&&!o,automaticPriorityReason:o?.automaticPriorityReason,pediatricReferral:!!o?.pediatricReferral}});const missing=contributions.filter(c=>c.missing).map(c=>c.variableId);const subtotals=Object.fromEntries(Object.keys(DIMENSIONS).map(d=>[d,contributions.filter(c=>c.dimension===d&&!c.missing).reduce((s,c)=>s+scoreValue(c.score),0)]));const total=Object.values(subtotals).reduce((a,b)=>a+b,0);const auto=contributions.map(c=>c.automaticPriorityReason).filter(Boolean);const numericPriority=calculatedPriority(total);const algorithmPriority=auto.length?1:numericPriority;const finalPriority=override?.to??algorithmPriority;return{total,subtotals,contributions,missing,pediatric:contributions.some(c=>c.pediatricReferral),status:contributions.some(c=>c.pediatricReferral)?'Requiere valoración mediante modelo pediátrico':missing.length?'Provisional por información incompleta':'Calculado',numericPriority,automaticPriority:auto.length?1:undefined,automaticPriorityReasons:auto,algorithmPriority,finalPriority,override,periodicity:{model:[...PERIODICITY.model.always,PERIODICITY.model.byPriority[finalPriority]],followUp:[...PERIODICITY.followUp.always]}}}
export function dimensionMaxima(){return Object.fromEntries(Object.keys(DIMENSIONS).map(d=>[d,VARIABLES.filter(v=>v.dimension===d).reduce((s,v)=>s+Math.max(...v.options.map(o=>scoreValue(o.score))),0)]))}export function totalMaximum(){return Object.values(dimensionMaxima()).reduce((a,b)=>a+b,0)}export function cumulativeInterventions(p){return (p===1?[3,2,1]:p===2?[3,2]:[3]).flatMap(level=>Object.entries(INTERVENTIONS[level]).flatMap(([category,items])=>items.map(text=>({priority:level,category,text}))))}export function normalizeText(s){return String(s??'').normalize('NFD').replace(/[\u0300-\u036f]/g,'').toLowerCase().replace(/\s+/g,' ').trim()}export function assertNoExcludedInterventions(){const bad=cumulativeInterventions(1).filter(i=>normalizeText(i.text).includes('problema relacionado con la medicacion')||normalizeText(i.text).includes('problemas relacionados con la medicacion'));if(bad.length)throw Error('Concepto excluido detectado')}export function exportJson(p){return JSON.stringify(p,null,2)}export function importJson(t){return JSON.parse(t)}export function exportCsv(rows){const keys=[...new Set(rows.flatMap(r=>Object.keys(r)))];return [keys.join(','),...rows.map(r=>keys.map(k=>JSON.stringify(r[k]??'')).join(','))].join('\n')}export function printableReport(context,legacyAnswers,legacyOverride){const data=typeof context==='object'&&context!==null&&!Array.isArray(context)?context:{pseudonym:context,answers:legacyAnswers,override:legacyOverride};const {pseudonym='Sin pseudónimo',hospital='',pharmacist='',answers={},override}=data;const r=scoreCase(answers,override);return`Resultado CMO-Migraña\nHospital/centro sanitario: ${hospital||'Pendiente'}\nFarmacéutico/a responsable: ${pharmacist||'Pendiente'}\nPaciente: ${pseudonym}\nPrioridad final: ${r.finalPriority}\nPuntuación: ${r.total}/${THRESHOLDS.totalMax}\nExplicación: ${r.contributions.map(c=>`${c.variable}: ${c.option??'pendiente'}${c.automaticPriorityReason?' (Prioridad 1 por '+c.automaticPriorityReason+')':' ('+(c.displayScore??'sin dato')+')'}`).join('; ')}\nPeriodicidad reevaluación: ${r.periodicity.model.join(' ')}\nPeriodicidad seguimiento: ${r.periodicity.followUp.join(' ')}\nIntervenciones: ${cumulativeInterventions(r.finalPriority).map(i=>`P${i.priority} · ${i.category}: ${i.text}`).join(' | ')}\nAviso legal: herramienta local de apoyo profesional, no sustitutiva del juicio clínico, sin finalidad diagnóstica o prescriptiva autónoma, no producto sanitario certificado y sujeta a validación, confidencialidad y cumplimiento RGPD/LOPDGDD.`}
